--
-- Name: resolve_patient_type(text, text, text, text, text, text, integer, date); Type: FUNCTION; Schema: clinic; Owner: postgres
--

CREATE FUNCTION clinic.resolve_patient_type(raw_type text, raw_role text DEFAULT NULL::text, patient_id text DEFAULT NULL::text, patient_name text DEFAULT NULL::text, patient_email text DEFAULT NULL::text, context_text text DEFAULT NULL::text, numeric_age integer DEFAULT NULL::integer, dob date DEFAULT NULL::date) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
  normalized_type TEXT := LOWER(TRIM(COALESCE(raw_type, '')));
  normalized_role TEXT := LOWER(TRIM(COALESCE(raw_role, '')));
  normalized_id TEXT := LOWER(TRIM(COALESCE(patient_id, '')));
  haystack TEXT := LOWER(CONCAT_WS(' ',
    COALESCE(patient_name, ''),
    COALESCE(patient_email, ''),
    COALESCE(context_text, ''),
    COALESCE(patient_id, '')
  ));
  derived_age INT;
BEGIN
  IF normalized_type IN ('student', 'teacher') THEN
    RETURN normalized_type;
  END IF;

  IF normalized_role IN ('student', 'teacher') THEN
    RETURN normalized_role;
  END IF;

  IF normalized_id ~ '^(stu|student)[-_:\/]' THEN
    RETURN 'student';
  END IF;

  IF normalized_id ~ '^(emp|teacher|faculty|staff)[-_:\/]' THEN
    RETURN 'teacher';
  END IF;

  IF haystack ~ '(teacher|faculty|professor|prof\.|instructor|staff|employee)' THEN
    RETURN 'teacher';
  END IF;

  IF haystack ~ '(student|learner|pupil)' THEN
    RETURN 'student';
  END IF;

  IF numeric_age IS NOT NULL AND numeric_age > 0 THEN
    IF numeric_age <= 23 THEN
      RETURN 'student';
    END IF;
    RETURN 'teacher';
  END IF;

  IF dob IS NOT NULL THEN
    derived_age := EXTRACT(YEAR FROM age(CURRENT_DATE, dob));
    IF derived_age <= 23 THEN
      RETURN 'student';
    END IF;
    RETURN 'teacher';
  END IF;

  RETURN 'student';
END;
$$;


ALTER FUNCTION clinic.resolve_patient_type(raw_type text, raw_role text, patient_id text, patient_name text, patient_email text, context_text text, numeric_age integer, dob date) OWNER TO postgres;

