--
-- Name: audit_research_status_change(); Type: FUNCTION; Schema: crad; Owner: postgres
--

CREATE FUNCTION crad.audit_research_status_change() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
  IF OLD.status IS DISTINCT FROM NEW.status THEN
    PERFORM crad.create_audit_log('RESEARCH_STATUS_CHANGE', 'Research ' || NEW.research_code || ' changed from ' || OLD.status || ' to ' || NEW.status, 'research', NEW.id);
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION crad.audit_research_status_change() OWNER TO postgres;

--
-- Name: create_audit_log(text, text, text, uuid); Type: FUNCTION; Schema: crad; Owner: postgres
--

CREATE FUNCTION crad.create_audit_log(_action text, _details text DEFAULT NULL::text, _entity_type text DEFAULT NULL::text, _entity_id uuid DEFAULT NULL::uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$ BEGIN INSERT INTO crad.audit_logs (user_id, action, details, entity_type, entity_id) VALUES (auth.uid(), _action, _details, _entity_type, _entity_id); END; $$;


ALTER FUNCTION crad.create_audit_log(_action text, _details text, _entity_type text, _entity_id uuid) OWNER TO postgres;

--
-- Name: generate_payment_code(); Type: FUNCTION; Schema: crad; Owner: postgres
--

CREATE FUNCTION crad.generate_payment_code() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE next_num INTEGER;
BEGIN
  SELECT COALESCE(MAX(CAST(SUBSTRING(payment_code FROM 'PAY-(\d+)') AS INTEGER)), 0) + 1 INTO next_num FROM crad.payments;
  NEW.payment_code := 'PAY-' || lpad(next_num::text, 4, '0');
  RETURN NEW;
END;
$$;


ALTER FUNCTION crad.generate_payment_code() OWNER TO postgres;

--
-- Name: generate_research_code(); Type: FUNCTION; Schema: crad; Owner: postgres
--

CREATE FUNCTION crad.generate_research_code() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public'
    AS $$
DECLARE next_num INTEGER;
BEGIN
  SELECT COALESCE(MAX(CAST(SUBSTRING(research_code FROM 'R-\d{4}-(\d+)') AS INTEGER)), 0) + 1 INTO next_num FROM crad.research;
  NEW.research_code := 'R-' || to_char(now(), 'YYYY') || '-' || lpad(next_num::text, 3, '0');
  RETURN NEW;
END;
$$;


ALTER FUNCTION crad.generate_research_code() OWNER TO postgres;

