--
-- Name: get_user_role(uuid); Type: FUNCTION; Schema: hr; Owner: postgres
--

CREATE FUNCTION hr.get_user_role(_user_id uuid) RETURNS hr.app_role
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
    SELECT role
    FROM hr.user_roles
    WHERE user_id = _user_id
    ORDER BY 
        CASE role 
            WHEN 'system_admin' THEN 1 
            WHEN 'hr_admin' THEN 2 
            WHEN 'employee' THEN 3 
            WHEN 'applicant' THEN 4 
        END
    LIMIT 1
$$;


ALTER FUNCTION hr.get_user_role(_user_id uuid) OWNER TO postgres;

