--
-- Name: dispatch_department_employee_directory(uuid, text, uuid, boolean, boolean, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.dispatch_department_employee_directory(_department_id uuid, _target_department_key text DEFAULT NULL::text, _requested_by uuid DEFAULT NULL::uuid, _only_primary boolean DEFAULT false, _include_inactive boolean DEFAULT false, _metadata jsonb DEFAULT '{}'::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    department_record RECORD;
    employee_record RECORD;
    dispatch_result JSONB;
    dispatch_results JSONB := '[]'::jsonb;
    attempted_employee_count INTEGER := 0;
    dispatched_employee_count INTEGER := 0;
    failed_employee_count INTEGER := 0;
    employee_success BOOLEAN;
BEGIN
    SELECT id, name, code
    INTO department_record
    FROM public.departments
    WHERE id = _department_id;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'ok', false,
            'status', 'not_found',
            'message', 'Department was not found.'
        );
    END IF;

    FOR employee_record IN
        SELECT employee_id, employee_number, employee_name, employment_status, first_name, last_name
        FROM public.employee_directory
        WHERE department_id = _department_id
          AND integration_ready = true
          AND (
              _include_inactive = true
              OR employment_status IN ('active', 'probation', 'on_leave')
          )
        ORDER BY last_name, first_name, employee_number
    LOOP
        attempted_employee_count := attempted_employee_count + 1;

        IF _target_department_key IS NULL THEN
            dispatch_result := public.dispatch_employee_profile_to_connected_departments(
                employee_record.employee_id,
                _requested_by,
                _only_primary,
                COALESCE(_metadata, '{}'::jsonb) || jsonb_build_object(
                    'sync_mode', 'department_directory',
                    'department_id', department_record.id,
                    'department_code', department_record.code,
                    'department_name', department_record.name
                )
            );

            employee_success := COALESCE(dispatch_result->>'ok', 'false') = 'true'
                OR COALESCE(dispatch_result->>'partial_success', 'false') = 'true';
        ELSE
            dispatch_result := public.dispatch_employee_profile_to_department(
                employee_record.employee_id,
                _target_department_key,
                'employee_profile_sync',
                _requested_by,
                COALESCE(_metadata, '{}'::jsonb) || jsonb_build_object(
                    'sync_mode', 'department_directory',
                    'department_id', department_record.id,
                    'department_code', department_record.code,
                    'department_name', department_record.name
                )
            );

            employee_success := COALESCE(dispatch_result->>'ok', 'false') = 'true';
        END IF;

        IF employee_success THEN
            dispatched_employee_count := dispatched_employee_count + 1;
        ELSE
            failed_employee_count := failed_employee_count + 1;
        END IF;

        dispatch_results := dispatch_results || jsonb_build_array(
            jsonb_build_object(
                'employee_id', employee_record.employee_id,
                'employee_number', employee_record.employee_number,
                'employee_name', employee_record.employee_name,
                'result', dispatch_result
            )
        );
    END LOOP;

    RETURN jsonb_build_object(
        'ok', attempted_employee_count > 0 AND failed_employee_count = 0,
        'partial_success', dispatched_employee_count > 0 AND failed_employee_count > 0,
        'status',
            CASE
                WHEN attempted_employee_count = 0 THEN 'no_employees'
                WHEN failed_employee_count = 0 THEN 'queued'
                WHEN dispatched_employee_count > 0 THEN 'partial'
                ELSE 'failed'
            END,
        'department_id', department_record.id,
        'department_name', department_record.name,
        'department_code', department_record.code,
        'attempted_employee_count', attempted_employee_count,
        'dispatched_employee_count', dispatched_employee_count,
        'failed_employee_count', failed_employee_count,
        'results', dispatch_results,
        'message',
            CASE
                WHEN attempted_employee_count = 0 THEN 'No integration-ready employees were found for this department.'
                WHEN failed_employee_count = 0 THEN 'Department employee directory sync queued successfully.'
                WHEN dispatched_employee_count > 0 THEN 'Department employee directory sync partially queued.'
                ELSE 'Department employee directory sync failed.'
            END
    );
END;
$$;


ALTER FUNCTION public.dispatch_department_employee_directory(_department_id uuid, _target_department_key text, _requested_by uuid, _only_primary boolean, _include_inactive boolean, _metadata jsonb) OWNER TO postgres;

--
-- Name: dispatch_department_flow(text, text, text, text, jsonb, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.dispatch_department_flow(_source_department_key text, _target_department_key text, _event_code text DEFAULT NULL::text, _source_record_id text DEFAULT NULL::text, _payload jsonb DEFAULT '{}'::jsonb, _requested_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    selected_route RECORD;
    new_event public.integration_flow_events%ROWTYPE;
    resolved_event_code TEXT;
    correlation TEXT;
BEGIN
    SELECT
        route.route_key,
        route.event_code,
        route.endpoint_path
    INTO selected_route
    FROM public.integration_flow_routes route
    WHERE route.source_department_key = _source_department_key
      AND route.target_department_key = _target_department_key
      AND route.is_active = true
      AND (_event_code IS NULL OR route.event_code = _event_code)
    ORDER BY route.priority ASC
    LIMIT 1;

    IF selected_route.route_key IS NULL THEN
        RETURN jsonb_build_object(
            'ok', false,
            'message', format(
                'No active integration route from %s to %s for event %s.',
                COALESCE(_source_department_key, 'unknown'),
                COALESCE(_target_department_key, 'unknown'),
                COALESCE(_event_code, 'default')
            ),
            'status', 'route_not_configured'
        );
    END IF;

    resolved_event_code := COALESCE(_event_code, selected_route.event_code);
    correlation := lower(
        concat(
            _source_department_key,
            '-',
            _target_department_key,
            '-',
            to_char(now(), 'YYYYMMDDHH24MISSMS'),
            '-',
            substring(replace(gen_random_uuid()::text, '-', '') from 1 for 8)
        )
    );

    INSERT INTO public.integration_flow_events (
        correlation_id,
        route_key,
        source_department_key,
        target_department_key,
        source_record_id,
        event_code,
        status,
        request_payload,
        response_payload,
        dispatch_endpoint,
        initiated_by,
        dispatched_at,
        metadata
    )
    VALUES (
        correlation,
        selected_route.route_key,
        _source_department_key,
        _target_department_key,
        _source_record_id,
        resolved_event_code,
        'queued',
        COALESCE(_payload, '{}'::jsonb),
        '{}'::jsonb,
        selected_route.endpoint_path,
        COALESCE(_requested_by, auth.uid()),
        now(),
        jsonb_build_object(
            'source_department_key', _source_department_key,
            'target_department_key', _target_department_key,
            'queued_from', 'hr_system'
        )
    )
    RETURNING * INTO new_event;

    RETURN jsonb_build_object(
        'ok', true,
        'event_id', new_event.id,
        'correlation_id', new_event.correlation_id,
        'route_key', new_event.route_key,
        'source_department_key', new_event.source_department_key,
        'target_department_key', new_event.target_department_key,
        'event_code', new_event.event_code,
        'status', new_event.status,
        'dispatch_endpoint', new_event.dispatch_endpoint,
        'message', 'Department flow queued successfully.'
    );
END;
$$;


ALTER FUNCTION public.dispatch_department_flow(_source_department_key text, _target_department_key text, _event_code text, _source_record_id text, _payload jsonb, _requested_by uuid) OWNER TO postgres;

--
-- Name: dispatch_employee_profile_to_connected_departments(uuid, uuid, boolean, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.dispatch_employee_profile_to_connected_departments(_employee_id uuid, _requested_by uuid DEFAULT NULL::uuid, _only_primary boolean DEFAULT false, _metadata jsonb DEFAULT '{}'::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    employee_record RECORD;
    target_config JSONB;
    dispatch_result JSONB;
    dispatch_results JSONB := '[]'::jsonb;
    attempted_target_count INTEGER := 0;
    dispatched_target_count INTEGER := 0;
    failed_target_count INTEGER := 0;
BEGIN
    SELECT *
    INTO employee_record
    FROM public.employee_directory
    WHERE employee_id = _employee_id;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'ok', false,
            'status', 'not_found',
            'message', 'Employee was not found in the integration directory.'
        );
    END IF;

    FOR target_config IN
        SELECT target
        FROM jsonb_array_elements(COALESCE(employee_record.connected_systems, '[]'::jsonb)) AS target(target)
        WHERE (
            _only_primary = false
            OR COALESCE((target->>'is_primary')::boolean, false) = true
        )
        ORDER BY
            COALESCE((target->>'is_primary')::boolean, false) DESC,
            COALESCE(target->>'department_name', '')
    LOOP
        attempted_target_count := attempted_target_count + 1;

        dispatch_result := public.dispatch_employee_profile_to_department(
            _employee_id,
            target_config->>'department_key',
            COALESCE(NULLIF(target_config->>'default_event_code', ''), 'employee_profile_sync'),
            _requested_by,
            COALESCE(_metadata, '{}'::jsonb) || jsonb_build_object(
                'dispatch_scope', CASE WHEN _only_primary THEN 'primary_target_only' ELSE 'all_connected_targets' END,
                'target_department_name', target_config->>'department_name'
            )
        );

        IF COALESCE(dispatch_result->>'ok', 'false') = 'true' THEN
            dispatched_target_count := dispatched_target_count + 1;
        ELSE
            failed_target_count := failed_target_count + 1;
        END IF;

        dispatch_results := dispatch_results || jsonb_build_array(
            jsonb_build_object(
                'target_department_key', target_config->>'department_key',
                'target_department_name', target_config->>'department_name',
                'event_code', COALESCE(NULLIF(target_config->>'default_event_code', ''), 'employee_profile_sync'),
                'result', dispatch_result
            )
        );
    END LOOP;

    IF attempted_target_count = 0 THEN
        RETURN jsonb_build_object(
            'ok', false,
            'status', 'target_not_configured',
            'employee_id', employee_record.employee_id,
            'employee_name', employee_record.employee_name,
            'attempted_target_count', 0,
            'dispatched_target_count', 0,
            'failed_target_count', 0,
            'results', dispatch_results,
            'message', 'No connected departments are configured for this employee.'
        );
    END IF;

    RETURN jsonb_build_object(
        'ok', failed_target_count = 0,
        'partial_success', dispatched_target_count > 0 AND failed_target_count > 0,
        'status',
            CASE
                WHEN failed_target_count = 0 THEN 'queued'
                WHEN dispatched_target_count > 0 THEN 'partial'
                ELSE 'failed'
            END,
        'employee_id', employee_record.employee_id,
        'employee_name', employee_record.employee_name,
        'attempted_target_count', attempted_target_count,
        'dispatched_target_count', dispatched_target_count,
        'failed_target_count', failed_target_count,
        'results', dispatch_results,
        'message',
            CASE
                WHEN failed_target_count = 0 THEN 'Employee profile dispatch queued for all configured departments.'
                WHEN dispatched_target_count > 0 THEN 'Employee profile dispatch queued for some departments, but some targets failed.'
                ELSE 'Employee profile dispatch failed for all configured departments.'
            END
    );
END;
$$;


ALTER FUNCTION public.dispatch_employee_profile_to_connected_departments(_employee_id uuid, _requested_by uuid, _only_primary boolean, _metadata jsonb) OWNER TO postgres;

--
-- Name: dispatch_hr_instructor_to_registrar(uuid, text, text, jsonb, jsonb, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.dispatch_hr_instructor_to_registrar(_instructor_id uuid, _college_unit text, _semester text, _teaching_load jsonb DEFAULT '[]'::jsonb, _schedule_matrix jsonb DEFAULT '{}'::jsonb, _remarks text DEFAULT NULL::text, _requested_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'hr'
    AS $$
DECLARE
    instructor_record RECORD;
    payload JSONB;
    source_record_id TEXT;
    result JSONB;
BEGIN
    SELECT *
    INTO instructor_record
    FROM hr.instructors instructor
    WHERE instructor.id = _instructor_id;

    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'ok', false,
            'status', 'not_found',
            'message', 'Instructor was not found in hr.instructors.'
        );
    END IF;

    IF COALESCE(instructor_record.integration_ready, false) = false THEN
        RETURN jsonb_build_object(
            'ok', false,
            'status', 'not_ready',
            'message', 'Instructor is not currently integration ready.'
        );
    END IF;

    payload := jsonb_strip_nulls(
        jsonb_build_object(
            'employee_id', instructor_record.employee_id,
            'employee_name', trim(concat_ws(' ', instructor_record.first_name, instructor_record.last_name)),
            'employee_number', instructor_record.employee_no,
            'department_name', instructor_record.department,
            'specialization', instructor_record.specialization,
            'academic_rank', instructor_record.academic_rank,
            'employment_status', instructor_record.employment_status,
            'college_unit', NULLIF(trim(COALESCE(_college_unit, '')), ''),
            'semester', NULLIF(trim(COALESCE(_semester, '')), ''),
            'teaching_load', COALESCE(_teaching_load, '[]'::jsonb),
            'schedule_matrix', COALESCE(_schedule_matrix, '{}'::jsonb),
            'remarks', NULLIF(trim(COALESCE(_remarks, '')), ''),
            'source_view', 'hr.instructors'
        )
    );

    source_record_id := format(
        'HR-INSTR-REG-%s-%s',
        COALESCE(NULLIF(instructor_record.employee_no, ''), substring(replace(instructor_record.employee_id::text, '-', '') FROM 1 FOR 8)),
        to_char(now(), 'YYYYMMDDHH24MISS')
    );

    result := public.dispatch_department_flow(
        'hr',
        'registrar',
        'faculty_assignment_validation',
        source_record_id,
        payload,
        _requested_by
    );

    RETURN result || jsonb_build_object(
        'instructor_id', instructor_record.employee_id,
        'employee_no', instructor_record.employee_no,
        'employee_name', trim(concat_ws(' ', instructor_record.first_name, instructor_record.last_name)),
        'college_unit', NULLIF(trim(COALESCE(_college_unit, '')), ''),
        'semester', NULLIF(trim(COALESCE(_semester, '')), '')
    );
END;
$$;


ALTER FUNCTION public.dispatch_hr_instructor_to_registrar(_instructor_id uuid, _college_unit text, _semester text, _teaching_load jsonb, _schedule_matrix jsonb, _remarks text, _requested_by uuid) OWNER TO postgres;

