--
-- Name: get_department_flow_events(text, text, text, text, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_department_flow_events(_department_key text DEFAULT 'hr'::text, _direction text DEFAULT 'all'::text, _status text DEFAULT NULL::text, _counterparty_department_key text DEFAULT NULL::text, _event_code text DEFAULT NULL::text, _limit integer DEFAULT 100) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    payload JSONB;
    resolved_direction TEXT;
BEGIN
    resolved_direction := lower(COALESCE(NULLIF(_direction, ''), 'all'));

    SELECT COALESCE(
        jsonb_agg(to_jsonb(event_row) ORDER BY event_row.created_at DESC),
        '[]'::jsonb
    )
    INTO payload
    FROM (
        SELECT
            event.id AS event_id,
            event.correlation_id,
            event.route_key,
            route.flow_name,
            event.source_department_key,
            source.department_name AS source_department_name,
            event.target_department_key,
            target.department_name AS target_department_name,
            CASE
                WHEN _department_key IS NULL THEN NULL
                WHEN event.source_department_key = _department_key THEN event.target_department_key
                WHEN event.target_department_key = _department_key THEN event.source_department_key
                ELSE NULL
            END AS counterparty_department_key,
            CASE
                WHEN _department_key IS NULL THEN NULL
                WHEN event.source_department_key = _department_key THEN target.department_name
                WHEN event.target_department_key = _department_key THEN source.department_name
                ELSE NULL
            END AS counterparty_department_name,
            event.source_record_id,
            event.event_code,
            event.status,
            event.dispatch_endpoint,
            event.request_payload,
            event.response_payload,
            event.initiated_by,
            event.dispatched_at,
            event.acknowledged_at,
            event.last_error,
            event.created_at,
            event.updated_at
        FROM public.integration_flow_events event
        JOIN public.integration_flow_routes route
          ON route.route_key = event.route_key
        JOIN public.integration_departments source
          ON source.department_key = event.source_department_key
        JOIN public.integration_departments target
          ON target.department_key = event.target_department_key
        WHERE (
            _department_key IS NULL
            OR (
                resolved_direction = 'incoming'
                AND event.target_department_key = _department_key
            )
            OR (
                resolved_direction = 'outgoing'
                AND event.source_department_key = _department_key
            )
            OR (
                resolved_direction = 'all'
                AND (
                    event.source_department_key = _department_key
                    OR event.target_department_key = _department_key
                )
            )
        )
          AND (_status IS NULL OR event.status = _status)
          AND (_event_code IS NULL OR event.event_code = _event_code)
          AND (
            _counterparty_department_key IS NULL
            OR _department_key IS NULL
            OR (
                event.source_department_key = _department_key
                AND event.target_department_key = _counterparty_department_key
            )
            OR (
                event.target_department_key = _department_key
                AND event.source_department_key = _counterparty_department_key
            )
          )
        ORDER BY event.created_at DESC
        LIMIT GREATEST(COALESCE(_limit, 100), 1)
    ) event_row;

    RETURN payload;
END;
$$;


ALTER FUNCTION public.get_department_flow_events(_department_key text, _direction text, _status text, _counterparty_department_key text, _event_code text, _limit integer) OWNER TO postgres;

--
-- Name: get_department_flow_status(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_department_flow_status(_event_id uuid DEFAULT NULL::uuid, _correlation_id text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    payload JSONB;
BEGIN
    SELECT jsonb_build_object(
        'ok', true,
        'event_id', event.id,
        'correlation_id', event.correlation_id,
        'route_key', event.route_key,
        'flow_name', route.flow_name,
        'source_department_key', event.source_department_key,
        'target_department_key', event.target_department_key,
        'event_code', event.event_code,
        'status', event.status,
        'dispatch_endpoint', event.dispatch_endpoint,
        'source_record_id', event.source_record_id,
        'request_payload', event.request_payload,
        'response_payload', event.response_payload,
        'initiated_by', event.initiated_by,
        'dispatched_at', event.dispatched_at,
        'acknowledged_at', event.acknowledged_at,
        'last_error', event.last_error,
        'created_at', event.created_at,
        'updated_at', event.updated_at
    )
    INTO payload
    FROM public.integration_flow_events event
    JOIN public.integration_flow_routes route
      ON route.route_key = event.route_key
    WHERE (_event_id IS NOT NULL AND event.id = _event_id)
       OR (_correlation_id IS NOT NULL AND event.correlation_id = _correlation_id)
    ORDER BY event.created_at DESC
    LIMIT 1;

    IF payload IS NULL THEN
        RETURN jsonb_build_object(
            'ok', false,
            'message', 'Integration event was not found.',
            'status', 'not_found'
        );
    END IF;

    RETURN payload;
END;
$$;


ALTER FUNCTION public.get_department_flow_status(_event_id uuid, _correlation_id text) OWNER TO postgres;

--
-- Name: get_department_integration_registry(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_department_integration_registry(_source_department_key text DEFAULT 'hr'::text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    result JSONB;
BEGIN
    SELECT COALESCE(
        jsonb_agg(
            jsonb_build_object(
                'department_key', registry.department_key,
                'department_name', registry.department_name,
                'system_code', registry.system_code,
                'module_directory', registry.module_directory,
                'purpose', registry.purpose,
                'default_action_label', registry.default_action_label,
                'dispatch_rpc_name', registry.dispatch_rpc_name,
                'status_rpc_name', registry.status_rpc_name,
                'ack_rpc_name', registry.ack_rpc_name,
                'dispatch_endpoint', '/rest/v1/rpc/' || registry.dispatch_rpc_name,
                'pending_count', registry.pending_count,
                'in_progress_count', registry.in_progress_count,
                'failed_count', registry.failed_count,
                'completed_count', registry.completed_count,
                'route_count', registry.route_count,
                'latest_status', registry.latest_status,
                'latest_event_code', registry.latest_event_code,
                'latest_correlation_id', registry.latest_correlation_id,
                'latest_created_at', registry.latest_created_at,
                'routes', registry.routes
            )
            ORDER BY registry.department_name
        ),
        '[]'::jsonb
    )
    INTO result
    FROM (
        SELECT
            target.department_key,
            target.department_name,
            target.system_code,
            target.module_directory,
            target.purpose,
            target.default_action_label,
            target.dispatch_rpc_name,
            target.status_rpc_name,
            target.ack_rpc_name,
            COUNT(DISTINCT route.id)::INT AS route_count,
            COUNT(event.id) FILTER (WHERE event.status IN ('queued', 'pending'))::INT AS pending_count,
            COUNT(event.id) FILTER (WHERE event.status IN ('dispatched', 'in_progress', 'awaiting_acknowledgement'))::INT AS in_progress_count,
            COUNT(event.id) FILTER (WHERE event.status IN ('failed', 'blocked'))::INT AS failed_count,
            COUNT(event.id) FILTER (WHERE event.status IN ('acknowledged', 'completed'))::INT AS completed_count,
            latest_event.status AS latest_status,
            latest_event.event_code AS latest_event_code,
            latest_event.correlation_id AS latest_correlation_id,
            latest_event.created_at AS latest_created_at,
            COALESCE(
                jsonb_agg(
                DISTINCT jsonb_build_object(
                    'route_key', route.route_key,
                    'flow_name', route.flow_name,
                    'event_code', route.event_code,
                    'endpoint_path', route.endpoint_path,
                    'priority', route.priority,
                    'is_required', route.is_required
                )
            ) FILTER (WHERE route.route_key IS NOT NULL),
            '[]'::jsonb
            ) AS routes
        FROM public.integration_departments target
        JOIN public.integration_flow_routes route
          ON target.department_key = route.target_department_key
         AND route.is_active = true
        LEFT JOIN public.integration_flow_events event
          ON event.route_key = route.route_key
        LEFT JOIN LATERAL (
            SELECT e.status, e.event_code, e.correlation_id, e.created_at
            FROM public.integration_flow_events e
            WHERE e.target_department_key = target.department_key
              AND (_source_department_key IS NULL OR e.source_department_key = _source_department_key)
            ORDER BY e.created_at DESC
            LIMIT 1
        ) latest_event ON true
        WHERE target.is_active = true
          AND (_source_department_key IS NULL OR route.source_department_key = _source_department_key)
        GROUP BY
            target.department_key,
            target.department_name,
            target.system_code,
            target.module_directory,
            target.purpose,
            target.default_action_label,
            target.dispatch_rpc_name,
            target.status_rpc_name,
            target.ack_rpc_name,
            latest_event.status,
            latest_event.event_code,
            latest_event.correlation_id,
            latest_event.created_at
    ) registry;

    RETURN result;
END;
$$;


ALTER FUNCTION public.get_department_integration_registry(_source_department_key text) OWNER TO postgres;

--
-- Name: get_hr_instructor_registrar_history(uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_hr_instructor_registrar_history(_instructor_id uuid, _limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    payload JSONB;
BEGIN
    SELECT COALESCE(
        jsonb_agg(to_jsonb(event_row) ORDER BY event_row.created_at DESC),
        '[]'::jsonb
    )
    INTO payload
    FROM (
        SELECT
            event.id AS event_id,
            event.correlation_id,
            event.route_key,
            route.flow_name,
            event.source_record_id,
            event.event_code,
            event.status,
            event.dispatch_endpoint,
            event.request_payload,
            event.response_payload,
            event.last_error,
            event.dispatched_at,
            event.acknowledged_at,
            event.created_at,
            event.updated_at
        FROM public.integration_flow_events event
        JOIN public.integration_flow_routes route
          ON route.route_key = event.route_key
        WHERE event.target_department_key = 'registrar'
          AND event.event_code = 'faculty_assignment_validation'
          AND event.request_payload->>'employee_id' = _instructor_id::text
        ORDER BY event.created_at DESC
        LIMIT GREATEST(COALESCE(_limit, 20), 1)
    ) event_row;

    RETURN payload;
END;
$$;


ALTER FUNCTION public.get_hr_instructor_registrar_history(_instructor_id uuid, _limit integer) OWNER TO postgres;

--
-- Name: get_hr_instructors(text, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_hr_instructors(_search text DEFAULT NULL::text, _employment_status text DEFAULT NULL::text, _limit integer DEFAULT 100) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public', 'hr'
    AS $$
DECLARE
    payload JSONB;
BEGIN
    SELECT COALESCE(
        jsonb_agg(to_jsonb(instructor_row) ORDER BY instructor_row.last_name, instructor_row.first_name, instructor_row.employee_no),
        '[]'::jsonb
    )
    INTO payload
    FROM (
        SELECT
            instructor.id,
            instructor.employee_id,
            instructor.employee_no,
            instructor.first_name,
            instructor.last_name,
            instructor.department,
            instructor.specialization,
            instructor.academic_rank,
            instructor.employment_status,
            instructor.primary_app_role,
            instructor.is_admin,
            instructor.connected_systems,
            instructor.integration_ready,
            instructor.created_at,
            instructor.updated_at
        FROM hr.instructors instructor
        WHERE (
            _search IS NULL
            OR trim(_search) = ''
            OR concat_ws(
                ' ',
                instructor.employee_no,
                instructor.first_name,
                instructor.last_name,
                instructor.department,
                instructor.specialization,
                instructor.academic_rank
            ) ILIKE '%' || trim(_search) || '%'
        )
          AND (
            _employment_status IS NULL
            OR trim(_employment_status) = ''
            OR instructor.employment_status = _employment_status
          )
        ORDER BY instructor.last_name, instructor.first_name, instructor.employee_no
        LIMIT GREATEST(COALESCE(_limit, 100), 1)
    ) instructor_row;

    RETURN payload;
END;
$$;


ALTER FUNCTION public.get_hr_instructors(_search text, _employment_status text, _limit integer) OWNER TO postgres;

