--
-- Name: is_conversation_creator(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.is_conversation_creator(_conversation_id uuid, _user_id uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.conversations conversation
    WHERE conversation.id = _conversation_id
      AND conversation.created_by = _user_id
  );
$$;


ALTER FUNCTION public.is_conversation_creator(_conversation_id uuid, _user_id uuid) OWNER TO postgres;

--
-- Name: is_conversation_participant(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.is_conversation_participant(_conversation_id uuid, _user_id uuid) RETURNS boolean
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.conversation_participants participant
    WHERE participant.conversation_id = _conversation_id
      AND participant.participant_id = _user_id
  );
$$;


