--
-- Name: pharmacy_medicines; Type: VIEW; Schema: cashier; Owner: postgres
--

CREATE VIEW cashier.pharmacy_medicines AS
 SELECT id,
    medicine_code,
    sku,
    medicine_name,
    brand_name,
    generic_name,
    category,
    medicine_type,
    dosage_strength,
    unit_of_measure,
    supplier_name,
    purchase_cost,
    selling_price,
    batch_lot_no,
    manufacturing_date,
    expiry_date,
    storage_requirements,
    reorder_level,
    low_stock_threshold,
    stock_capacity,
    stock_on_hand,
    stock_location,
    barcode,
    is_archived,
    created_at,
    updated_at
   FROM clinic.pharmacy_medicines;


ALTER VIEW cashier.pharmacy_medicines OWNER TO postgres;

--
-- Name: pharmacy_stock_movements; Type: TABLE; Schema: clinic; Owner: postgres
--

CREATE TABLE clinic.pharmacy_stock_movements (
    id bigint NOT NULL,
    medicine_id bigint NOT NULL,
    movement_type character varying(30) NOT NULL,
    quantity_change integer DEFAULT 0 NOT NULL,
    quantity_before integer DEFAULT 0 NOT NULL,
    quantity_after integer DEFAULT 0 NOT NULL,
    reason text,
    batch_lot_no character varying(80),
    stock_location character varying(120),
    actor character varying(120) NOT NULL,
    created_at timestamp without time zone DEFAULT now() NOT NULL,
    CONSTRAINT pharmacy_stock_movements_movement_type_check CHECK (((movement_type)::text = ANY ((ARRAY['add'::character varying, 'restock'::character varying, 'dispense'::character varying, 'adjust'::character varying, 'archive'::character varying, 'alert'::character varying])::text[])))
);


ALTER TABLE clinic.pharmacy_stock_movements OWNER TO postgres;

