--
-- Name: dashboard_summary; Type: VIEW; Schema: comlab; Owner: postgres
--

CREATE VIEW comlab.dashboard_summary AS
 SELECT ( SELECT count(*) AS count
           FROM comlab.users
          WHERE (users.is_active = 1)) AS total_active_users,
    ( SELECT count(*) AS count
           FROM comlab.users
          WHERE ((users.role = 'Administrator'::text) AND (users.is_active = 1))) AS total_admins,
    ( SELECT count(*) AS count
           FROM comlab.users
          WHERE ((users.role = 'Faculty'::text) AND (users.is_active = 1))) AS total_faculty,
    ( SELECT count(*) AS count
           FROM comlab.devices) AS total_devices,
    ( SELECT count(*) AS count
           FROM comlab.devices
          WHERE (devices.status = 'Available'::text)) AS devices_available,
    ( SELECT count(*) AS count
           FROM comlab.devices
          WHERE (devices.status = 'Under Repair'::text)) AS devices_under_repair,
    ( SELECT count(*) AS count
           FROM comlab.devices
          WHERE (devices.status = 'Damaged'::text)) AS devices_damaged,
    ( SELECT count(*) AS count
           FROM comlab.locations
          WHERE (locations.is_active = 1)) AS total_labs,
    ( SELECT count(*) AS count
           FROM comlab.faculty_schedules
          WHERE (faculty_schedules.is_active = 1)) AS active_schedules,
    ( SELECT count(*) AS count
           FROM comlab.requests
          WHERE (requests.status = 'Pending'::text)) AS pending_requests;


ALTER VIEW comlab.dashboard_summary OWNER TO postgres;

