    CONSTRAINT integration_documents_status_check CHECK ((status = ANY (ARRAY['draft'::text, 'sent'::text, 'received'::text, 'acknowledged'::text, 'archived'::text]))),
    CONSTRAINT integration_documents_subject_type_check CHECK ((subject_type = ANY (ARRAY['student'::text, 'staff'::text, 'faculty'::text, 'general'::text, 'system'::text])))
);


