    assigned_doctor character varying(120) DEFAULT 'Unassigned'::character varying NOT NULL,
    source character varying(50) DEFAULT 'appointment_confirmed'::character varying NOT NULL,
    status character varying(40) DEFAULT 'intake'::character varying NOT NULL,
    chief_complaint text,
    diagnosis text,
    clinical_notes text,
    consultation_started_at timestamp without time zone,
    lab_requested smallint DEFAULT 0 NOT NULL,
    lab_result_ready smallint DEFAULT 0 NOT NULL,
    prescription_created smallint DEFAULT 0 NOT NULL,
    prescription_dispensed smallint DEFAULT 0 NOT NULL,
    follow_up_date date,
    is_emergency smallint DEFAULT 0 NOT NULL,
    version integer DEFAULT 1 NOT NULL,
    created_at timestamp without time zone DEFAULT now() NOT NULL,
    updated_at timestamp without time zone DEFAULT now() NOT NULL,
    patient_type character varying(20) DEFAULT 'student'::character varying NOT NULL,
    cashier_billing_id bigint,
    cashier_billing_no character varying(120),
    cashier_payment_status character varying(20) DEFAULT 'unpaid'::character varying NOT NULL,
    cashier_can_proceed smallint DEFAULT 0 NOT NULL,
    cashier_verified_at timestamp with time zone,
    CONSTRAINT checkup_visits_patient_type_check CHECK (((patient_type)::text = ANY ((ARRAY['student'::character varying, 'teacher'::character varying])::text[])))
);


