--
-- Name: laboratory_requests; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.laboratory_requests (
    id bigint NOT NULL,
    request_code character varying(40) NOT NULL,
    visit_id character varying(40),
    patient_id character varying(60),
    patient_name character varying(150) NOT NULL,
    age smallint,
    sex character varying(20),
    requested_by_doctor character varying(120) NOT NULL,
    doctor_department character varying(120),
    category character varying(80) NOT NULL,
    priority character varying(20) DEFAULT 'Normal'::character varying NOT NULL,
    status character varying(20) DEFAULT 'Pending'::character varying NOT NULL,
    specimen_type character varying(80),
    sample_source character varying(80),
    collection_datetime timestamp without time zone,
    clinical_diagnosis text,
    clinical_notes text,
    lab_instructions text,
    insurance_reference character varying(120),
    billing_reference character varying(120),
    assigned_lab_staff character varying(120),
    sample_collected smallint DEFAULT 0 NOT NULL,
    sample_collected_at timestamp without time zone,
    processing_started_at timestamp without time zone,
    result_encoded_at timestamp without time zone,
    result_reference_range text,
    verified_by character varying(120),
    verified_at timestamp without time zone,
    rejection_reason text,
    resample_flag smallint DEFAULT 0 NOT NULL,
    released_at timestamp without time zone,
    raw_attachment_name character varying(255),
    encoded_values jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp without time zone DEFAULT now() NOT NULL,
    updated_at timestamp without time zone DEFAULT now() NOT NULL,
    requested_at timestamp without time zone DEFAULT now() NOT NULL,
    patient_type character varying(20) DEFAULT 'student'::character varying NOT NULL,
    cashier_billing_id bigint,
    cashier_payment_status character varying(20) DEFAULT 'unpaid'::character varying NOT NULL,
    cashier_can_proceed smallint DEFAULT 0 NOT NULL,
    cashier_verified_at timestamp with time zone,
    CONSTRAINT laboratory_requests_age_check CHECK (((age >= 0) AND (age <= 120))),
    CONSTRAINT laboratory_requests_patient_type_check CHECK (((patient_type)::text = ANY ((ARRAY['student'::character varying, 'teacher'::character varying])::text[]))),
    CONSTRAINT laboratory_requests_priority_check CHECK (((priority)::text = ANY ((ARRAY['Normal'::character varying, 'Urgent'::character varying, 'STAT'::character varying])::text[]))),
    CONSTRAINT laboratory_requests_status_check CHECK (((status)::text = ANY ((ARRAY['Pending'::character varying, 'In Progress'::character varying, 'Result Ready'::character varying, 'Completed'::character varying, 'Cancelled'::character varying])::text[])))
);


ALTER TABLE public.laboratory_requests OWNER TO postgres;

