-- Name: patient_walkins; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.patient_walkins (
    id bigint NOT NULL,
    case_id character varying(40) NOT NULL,
    patient_name character varying(150) NOT NULL,
    age smallint,
    sex character varying(12),
    date_of_birth date,
    contact character varying(80),
    address text,
    emergency_contact character varying(120),
    patient_ref character varying(60),
    visit_department character varying(80),
    checkin_time timestamp without time zone,
    pain_scale smallint,
    temperature_c numeric(4,1),
    blood_pressure character varying(20),
    pulse_bpm smallint,
    weight_kg numeric(5,2),
    chief_complaint text,
    severity character varying(20) DEFAULT 'Low'::character varying NOT NULL,
    intake_time timestamp without time zone DEFAULT now() NOT NULL,
    assigned_doctor character varying(120) DEFAULT 'Nurse Triage'::character varying NOT NULL,
    status character varying(30) DEFAULT 'waiting'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT now() NOT NULL,
    updated_at timestamp without time zone DEFAULT now() NOT NULL,
    patient_type character varying(20) DEFAULT 'student'::character varying NOT NULL,
    CONSTRAINT patient_walkins_age_check CHECK (((age >= 0) AND (age <= 120))),
    CONSTRAINT patient_walkins_pain_scale_check CHECK (((pain_scale >= 0) AND (pain_scale <= 10))),
    CONSTRAINT patient_walkins_patient_type_check CHECK (((patient_type)::text = ANY ((ARRAY['student'::character varying, 'teacher'::character varying])::text[]))),
    CONSTRAINT patient_walkins_pulse_bpm_check CHECK (((pulse_bpm >= 20) AND (pulse_bpm <= 240))),
    CONSTRAINT patient_walkins_severity_check CHECK (((severity)::text = ANY ((ARRAY['Low'::character varying, 'Moderate'::character varying, 'Emergency'::character varying])::text[]))),
    CONSTRAINT patient_walkins_sex_check CHECK (((sex)::text = ANY ((ARRAY['Male'::character varying, 'Female'::character varying, 'Other'::character varying])::text[]))),
    CONSTRAINT patient_walkins_temperature_c_check CHECK (((temperature_c >= (30)::numeric) AND (temperature_c <= (45)::numeric))),
    CONSTRAINT patient_walkins_weight_kg_check CHECK ((weight_kg > (0)::numeric))
);


ALTER TABLE public.patient_walkins OWNER TO postgres;

