ALTER TABLE registrar.students OWNER TO postgres;

--
-- Name: student_subject_loads; Type: VIEW; Schema: registrar; Owner: postgres
--

CREATE VIEW registrar.student_subject_loads AS
 SELECT students.id AS student_id,
    students.student_no,
    (count(enrollments.id))::integer AS subject_count,
    COALESCE(string_agg(classes.class_code, ', '::text ORDER BY classes.class_code) FILTER (WHERE (classes.id IS NOT NULL)), ''::text) AS subject_codes,
    COALESCE(jsonb_agg(jsonb_build_object('class_id', classes.id, 'class_code', classes.class_code, 'title', classes.title, 'course', classes.course, 'units', classes.units, 'enrollment_status', enrollments.status) ORDER BY classes.class_code) FILTER (WHERE (classes.id IS NOT NULL)), '[]'::jsonb) AS subject_load
   FROM ((registrar.students students
     LEFT JOIN registrar.enrollments enrollments ON ((enrollments.student_id = students.id)))
     LEFT JOIN registrar.classes classes ON ((classes.id = enrollments.class_id)))
  GROUP BY students.id, students.student_no;


ALTER VIEW registrar.student_subject_loads OWNER TO postgres;

--
-- Name: student_directory; Type: VIEW; Schema: registrar; Owner: postgres
--

CREATE VIEW registrar.student_directory AS
 SELECT students.id AS student_id,
    students.student_no,
    students.first_name,
    COALESCE(students.middle_name, ''::text) AS middle_name,
    students.last_name,
    concat_ws(' '::text, students.first_name, NULLIF(students.middle_name, ''::text), students.last_name) AS student_name,
    students.program,
    students.year_level,
    COALESCE(students.section_name, ''::text) AS section_name,
    students.status AS registrar_status,
    COALESCE(enrollment_summary.enrollment_status, NULLIF(students.status, ''::text), 'Active'::text) AS enrollment_status,
    concat_ws(' / '::text, NULLIF(students.program, ''::text), NULLIF(students.year_level, ''::text), NULLIF(students.section_name, ''::text)) AS course_year_section,
    COALESCE(students.email, ''::text) AS email,
    COALESCE(students.phone, ''::text) AS phone,
    COALESCE(subject_loads.subject_count, 0) AS subject_count,
    COALESCE(subject_loads.subject_codes, ''::text) AS subject_codes,
    COALESCE(subject_loads.subject_load, '[]'::jsonb) AS subject_load,
    students.created_at
   FROM ((registrar.students students
     LEFT JOIN LATERAL ( SELECT COALESCE(max(
                CASE
                    WHEN (enrollments.status ~~* 'enrolled%'::text) THEN enrollments.status
                    ELSE NULL::text
                END), max(NULLIF(enrollments.status, ''::text))) AS enrollment_status
           FROM registrar.enrollments enrollments
          WHERE (enrollments.student_id = students.id)) enrollment_summary ON (true))
     LEFT JOIN registrar.student_subject_loads subject_loads ON ((subject_loads.student_id = students.id)));


ALTER VIEW registrar.student_directory OWNER TO postgres;

--
-- Name: registrar_student_directory; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.registrar_student_directory AS
 SELECT student_id,
    student_no,
    first_name,
    middle_name,
    last_name,
    student_name,
    program,
    year_level,
    section_name,
    registrar_status,
    enrollment_status,
    course_year_section,
    email,
    phone,
    subject_count,
    subject_codes,
    subject_load,
    created_at
   FROM registrar.student_directory;


ALTER VIEW public.registrar_student_directory OWNER TO postgres;

