--
-- Name: faculty_presence_summary _RETURN; Type: RULE; Schema: comlab; Owner: postgres
--

CREATE OR REPLACE VIEW comlab.faculty_presence_summary AS
 SELECT u.user_id,
    concat(u.first_name, ' ', u.last_name) AS faculty_name,
    u.department,
    count(DISTINCT fs.schedule_id) AS active_schedules,
    count(sa.attendance_id) AS total_sessions,
    sum(
        CASE
            WHEN (sa.status = 'Present'::text) THEN 1
            ELSE 0
        END) AS present_count,
    sum(
        CASE
            WHEN (sa.status = 'Absent'::text) THEN 1
            ELSE 0
        END) AS absent_count,
    sum(
        CASE
            WHEN (sa.status = 'Excused'::text) THEN 1
            ELSE 0
        END) AS excused_count,
    round(((100.0 * (sum(
        CASE
            WHEN (sa.status = 'Present'::text) THEN 1
            ELSE 0
        END))::numeric) / (NULLIF(count(sa.attendance_id), 0))::numeric), 1) AS attendance_rate_pct
   FROM ((comlab.users u
     LEFT JOIN comlab.faculty_schedules fs ON (((fs.faculty_id = u.user_id) AND (fs.is_active = 1))))
     LEFT JOIN comlab.schedule_attendance sa ON ((sa.faculty_id = u.user_id)))
  WHERE ((u.role = 'Faculty'::text) AND (u.is_active = 1))
  GROUP BY u.user_id;


