-- Name: conversations Create conversations; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Create conversations" ON public.conversations FOR INSERT TO authenticated WITH CHECK ((created_by = auth.uid()));


--
-- Name: conversation_messages Delete conversation messages; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Delete conversation messages" ON public.conversation_messages FOR DELETE TO authenticated USING (((sender_id = auth.uid()) OR prefect.has_role(auth.uid(), 'admin'::prefect.app_role)));


--
-- Name: conversation_participants Delete conversation participants; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Delete conversation participants" ON public.conversation_participants FOR DELETE TO authenticated USING (((participant_id = auth.uid()) OR prefect.has_role(auth.uid(), 'admin'::prefect.app_role) OR public.is_conversation_creator(conversation_id, auth.uid())));


--
-- Name: conversations Delete conversations; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Delete conversations" ON public.conversations FOR DELETE TO authenticated USING (((created_by = auth.uid()) OR prefect.has_role(auth.uid(), 'admin'::prefect.app_role)));


--
-- Name: conversation_messages Insert conversation messages; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Insert conversation messages" ON public.conversation_messages FOR INSERT TO authenticated WITH CHECK (((sender_id = auth.uid()) AND public.is_conversation_participant(conversation_id, auth.uid())));


--
-- Name: conversation_participants Insert conversation participants; Type: POLICY; Schema: public; Owner: postgres
--

