--
-- Name: conversation_participants Update conversation participants; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "Update conversation participants" ON public.conversation_participants FOR UPDATE TO authenticated USING (((participant_id = auth.uid()) OR prefect.has_role(auth.uid(), 'admin'::prefect.app_role) OR public.is_conversation_creator(conversation_id, auth.uid()))) WITH CHECK (((participant_id = auth.uid()) OR prefect.has_role(auth.uid(), 'admin'::prefect.app_role) OR public.is_conversation_creator(conversation_id, auth.uid())));


