--
-- Name: conversation_messages View conversation messages; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "View conversation messages" ON public.conversation_messages FOR SELECT TO authenticated USING (((sender_id = auth.uid()) OR prefect.has_role(auth.uid(), 'admin'::prefect.app_role) OR public.is_conversation_participant(conversation_id, auth.uid()) OR public.is_conversation_creator(conversation_id, auth.uid())));


--
-- Name: conversation_participants View conversation participants; Type: POLICY; Schema: public; Owner: postgres
--

